const percentSdrEmptyNewConversationsnOfNewConversations = 
  percentOf(dados.sdr_empty_new_conversations, dados.sdr_new_conversation);

const percentSdrAtLeastOneInteractionOfSdrActive = 
  percentOf(dados.sdr_count_at_least_one_full_interaction, dados.sdr_active_conversations);

const percentSdrMoreThanOneInteractionOfSdrActive = 
  percentOf(dados.sdr_count_more_than_one_full_interaction, dados.sdr_active_conversations);

const percentSdrThreeOrMoreInteractionOfSdrActive = 
