const percentSdrAgentReplyLeadOfSdrActive = 
  percentOf(dados.sdr_count_last_message_was_agent, dados.sdr_active_conversations);

const percentSdrAgentReplyLeadOnNewConversationOfSdrActive =
  percentOf((Number(dados.sdr_active_conversations) - 
               Number(dados.sdr_agent_count_missed_first_response_on_new_conversation)),
            dados.sdr_active_conversations)

const percentQualifiedLeadsOfSdrActiveConversations =
  percentOf(dados.count_qualified_leads, dados.sdr_active_conversations)

const percentQualifiedLeadsOfSdrEngagedLeads =
  percentOf(dados.count_qualified_leads, dados.sdr_engaged_leads)

const countResponseQualifiedFirstResponse =
  Number(dados.count_qualified_leads) - Number(dados.sales_agent_count_missed_first_response)

const percentResponseFirstResponseOfQualifieds = 
  percentOf(countResponseQualifiedFirstResponse, dados.count_qualified_leads)

const percentSalesNotEmptyNewConversationsnOfSalesActive = 
  percentOf(dados.sales_not_empty_new_conversations, dados.sales_active_conversations);

const percentSalesEngagedOfActive = 
  percentOf(dados.sales_engaged_leads, dados.sales_active_conversations);

const percentSalesAgentNotReplyFirstLeadOfSdrActive =
  percentOf(dados.sales_agent_count_missed_first_response, dados.sales_active_conversations);

const percentSalesCountLastMessageWasLeadOfSdrActive = 
  percentOf(dados.sales_count_last_message_was_lead, dados.sales_active_conversations);

const percentSalesLeadCountMissedFirstResponseOfActiveConversations =
  percentOf(dados.sales_lead_count_missed_first_response, dados.sales_active_conversations);

const avgTimeToQualify = formatTime(Number(dados.avg_qualifying_time_seconds))



const skipNormalizationObjects = [
  'sdr_time_interactions', 
  'sdr_weekday_interactions',
  'sdr_inboxes_info',
  'sales_inboxes_info',
  'sales_labels',
  'sdr_labels'
];

const normalizeTime = [
  'agent_avg_response_time_seconds' ,
  'sdr_agent_avg_response_time_seconds' ,
  'agent_avg_first_response_time',
  'sdr_agent_avg_first_response_time',
  'sdr_agent_avg_first_response_time_norm',
  'sdr_agent_avg_response_time_seconds_norm_this_period',
  'sales_agent_avg_first_response_time',
  'sales_agent_avg_response_time_seconds',
  'sales_agent_avg_response_time_seconds_norm_this_period',
  'sales_agent_avg_first_response_time_norm',
  'avg_qualifying_time_seconds'
];

const normalizeFloat = [
 'sdr_avg_interactions',
  'sdr_avg_interactions_per_qualified_lead',
  'sales_avg_interactions',
]

const formattedMessagesData = {};
for (let key in dados) {
  if (skipNormalizationObjects.includes(key))
    continue

  if (normalizeFloat.includes(key)) {
    formattedMessagesData[key] = dados[key] != null 
      ? formatNumber(Number(dados[key]), 1, 2)
      : null;
  } else {
    formattedMessagesData[key] = dados[key] != null 
      ? formatNumber(Number(dados[key]), 0, 0)
      : null;
  }

  if (dados[key] != null 
      && normalizeTime.includes(key)
  ) {

      formattedMessagesData[key].formatPtBr =
        formatTime(formattedMessagesData[key].number);
  }
}

const convertionsPrevious = null;
const converstionsCurrent = null;

const convertions = $itemIndex == 0 ? convertionsPrevious : converstionsCurrent;

const percentConvertionOfQualifieds = convertions
  ? percentOf(convertions, dados.count_qualified_leads)
  : null


const sdrTimeInteractions = dados.sdr_time_interactions;

let totalTimeInteractions = 0;
for (let i = 0; i < sdrTimeInteractions.length; ++i) {
  totalTimeInteractions +=
    sdrTimeInteractions.at(i).count_interactions_hour_of_day;
}

function formatHourInterval(hour) {
  const startHour = hour.toString().padStart(2, '0');
  const nextHour = hour + 1;
  const endHour = nextHour.toString().padStart(2, '0');

  return `${startHour}:00-${endHour}:00`;
}

let frequencyHourTable = {};
for (let i = 0; i < 24; ++i) {
  frequencyHourTable[i] = {
    hourInterval: formatHourInterval(i),
    frequency: 0,
    percent: {number: 0, formatPtBr: "0,00"},
  }
}


for (let i = 0; i < sdrTimeInteractions.length; ++i) {
  const item = sdrTimeInteractions[i];
  frequencyHourTable[item.hour_of_day].frequency =
    item.count_interactions_hour_of_day
  frequencyHourTable[item.hour_of_day].percent =
    percentOf(
      frequencyHourTable[item.hour_of_day].frequency,
      totalTimeInteractions)
}

const sortedFrequencies = Object.entries(frequencyHourTable)
  .sort((a, b) => b[1].frequency - a[1].frequency);

const sdrWeekdayInteractions = dados.sdr_weekday_interactions;

let totalWeekdayInteractions = 0;
for (let i = 0; i < sdrWeekdayInteractions.length; ++i) {
  totalWeekdayInteractions +=
    sdrWeekdayInteractions.at(i).count_interactions_day_of_week;
}

function formatWeekday(weekday) {
  switch(weekday) {
    case 1: return ["Segunda", "Seg"];
    case 2: return ["Terça"  , "Ter"];
    case 3: return ["Quarta" , "Qua"];
    case 4: return ["Quinta" , "Qui"];
    case 5: return ["Sexta"  , "Sex"];
    case 6: return ["Sábado" , "Sab"];
    case 7: return ["Domingo", "Dom"];
  }
  return null;
}

let frequencyWeekdayTable = {};
for (let i = 1; i <= 7; ++i) {
  const [weekdayLong, weekdayShort] = formatWeekday(i);
  frequencyWeekdayTable[i] = {
    weekdayLong,
    weekdayShort,
    frequency: 0,
    percent: {number: 0, formatPtBr: "0,00"},
  }
}

for (let i = 0; i < sdrWeekdayInteractions.length; ++i) {
  const item = sdrWeekdayInteractions[i];
  frequencyWeekdayTable[item.day_of_week].frequency =
    item.count_interactions_day_of_week
  frequencyWeekdayTable[item.day_of_week].percent =
    percentOf(
      frequencyWeekdayTable[item.day_of_week].frequency,
      totalWeekdayInteractions)
}

// sdrInboxes
const sdrInboxInteractions = dados.sdr_inboxes_info;
let sdrInboxTable = {};
for (let i = 0; i < sdrInboxInteractions.length; ++i) {

  sdrInboxTable[sdrInboxInteractions[i].inbox_name] = {
    interactions: formatNumber(sdrInboxInteractions[i].interactions_this_period, 0, 0),
    newConversationsNotEmpty: formatNumber(sdrInboxInteractions[i].not_empty_new_conversations, 0, 0),
    activeConversations: formatNumber(sdrInboxInteractions[i].total_active_conversations, 0, 0),
    engagedLeads: formatNumber(sdrInboxInteractions[i].engaged_leads, 0, 0),
    qualifiedleadCount: formatNumber(sdrInboxInteractions[i].count_qualified_leads, 0, 0),
    percentSdrInteractions:  percentOf(
      sdrInboxInteractions[i].interactions_this_period,
      dados.sdr_interactions_this_period),
    avgInteractions: formatNumber(
      sdrInboxInteractions[i].sdr_avg_interactions, 1, 2),
    avgInteractionsToQualify: formatNumber(
      sdrInboxInteractions[i].sdr_avg_interactions_per_qualified_lead, 1, 2),
    avgTimeToQualify: formatTime(
      Number(sdrInboxInteractions[i].avg_qualifying_time_seconds)
    ),
    qualificationPerEngagedLead: percentOf(sdrInboxInteractions[i].count_qualified_leads,
                  sdrInboxInteractions[i].engaged_leads),
    qualificationPerActiveConversation: 
      percentOf(sdrInboxInteractions[i].count_qualified_leads,
                  sdrInboxInteractions[i].total_active_conversations),
    leadNotReplyFirst: formatNumber(sdrInboxInteractions[i].lead_count_missed_first_response, 0, 0),
    percentLeadNotReplyFirstOfActiveConversations: 
      percentOf(
        sdrInboxInteractions[i].lead_count_missed_first_response,
        sdrInboxInteractions[i].total_active_conversations
      ),
    agentAvgResponseTimeSecondsThisPeriod:
      formatTime(Number(sdrInboxInteractions[i].agent_avg_response_time_seconds_this_period)),
    totalSentLinks: formatNumber(sdrInboxInteractions[i].total_sent_links, 0, 0),
  };
}

sdrInboxTable["Total"] = {
  interactions: formattedMessagesData.sdr_interactions_this_period,
  newConversationsNotEmpty: formattedMessagesData.not_empty_new_conversations,
  activeConversations: formattedMessagesData.sdr_active_conversations,
  engagedLeads: formattedMessagesData.sdr_engaged_leads,
  qualifiedleadCount: formattedMessagesData.count_qualified_leads,
  percentSdrInteractions: {number: 100, formatPtBr: "100,00"},
  avgInteractions: formatNumber(
      Number(dados.sdr_avg_interactions)),
  avgInteractionsToQualify: formatNumber(
      Number(dados.sdr_avg_interactions_per_qualified_lead)),
  avgTimeToQualify: avgTimeToQualify,
  qualificationPerEngagedLead:
    percentQualifiedLeadsOfSdrEngagedLeads,
  qualificationPerActiveConversation:
    percentQualifiedLeadsOfSdrActiveConversations,
  leadNotReplyFirst: formattedMessagesData.sdr_lead_count_missed_first_response,
  percentLeadNotReplyFirstOfActiveConversations: 
      percentSdrLeadNotReplyFirstAgentOfSdrActive,
  agentAvgResponseTimeSecondsThisPeriod:
      formatTime(dados.sdr_agent_avg_response_time_seconds),
  totalSentLinks: formattedMessagesData.sdr_sent_links,
}// sdrInboxes

// salesInboxes
const salesInboxInteractions = dados.sales_inboxes_info;
let salesInboxTable = {};
for (let i = 0; i < salesInboxInteractions.length; ++i) {

  salesInboxTable[salesInboxInteractions[i].inbox_name] = {
    interactions: formatNumber(salesInboxInteractions[i].interactions_this_period, 0, 0),
    newConversationsNotEmpty: formatNumber(salesInboxInteractions[i].not_empty_new_conversations, 0, 0),
    activeConversations: formatNumber(salesInboxInteractions[i].total_active_conversations, 0, 0),
    engagedLeads: formatNumber(salesInboxInteractions[i].engaged_leads, 0, 0),
    percentEngagedOfActive: 
