      salesInboxInteractions[i].interactions_this_period,
      dados.sales_interactions_this_period),
    avgInteractions: formatNumber(
      salesInboxInteractions[i].sales_avg_interactions),
    leadNotReplyFirst:
      formatNumber(salesInboxInteractions[i].lead_count_missed_first_response, 0, 0),
    agentNotReplyFirst:
      formatNumber(salesInboxInteractions[i].agent_count_missed_first_response, 0, 0),
    percentLeadNotReplyFirstOfActiveConversations: 
      percentOf(
        salesInboxInteractions[i].lead_count_missed_first_response,
        salesInboxInteractions[i].total_active_conversations
      ),
    agentAvgResponseTimeSecondsThisPeriod:
      formatTime(Number(salesInboxInteractions[i].agent_avg_response_time_seconds_this_period)),
    agentAvgResponseTimeSecondsThisPeriodNorm:
formatTime(salesInboxInteractions[i].agent_avg_response_time_seconds_norm_this_period),
    agentAvgFirstResponseTimeSeconds: formatTime(salesInboxInteractions[i].agent_avg_first_response_time_seconds),
    agentAvgFirstResponseTimeSecondsNorm: formatTime(salesInboxInteractions[i].agent_avg_first_response_time_seconds_norm),
    countLastMessageWasAgent: formatNumber(salesInboxInteractions[i].count_last_message_was_agent, 0, 0),
    countLastMessageWasContact: 
  formatNumber(salesInboxInteractions[i].count_last_message_was_lead, 0, 0),
    totalSentLinks: formatNumber(salesInboxInteractions[i].total_sent_links, 0, 0),
  };
}

salesInboxTable["Total"] = {
  interactions: formattedMessagesData.sales_interactions_this_period,
  newConversationsNotEmpty: formattedMessagesData.sales_not_empty_new_conversations,
  activeConversations: formattedMessagesData.sales_active_conversations,
  engagedLeads: formattedMessagesData.sales_engaged_leads,
  percentEngagedOfActive: percentOf(dados.sales_engaged_leads, dados.sales_active_conversations),
  percentSalesInteractions: {number: 100, formatPtBr: "100,00"},
  avgInteractions: formatNumber(
      Number(dados.sales_avg_interactions), 1, 2),
  avgInteractionsToQualify: formatNumber(
      Number(dados.sales_avg_interactions_per_qualified_lead), 1, 2),
  avgTimeToQualify: avgTimeToQualify,
  leadNotReplyFirst: formattedMessagesData.sales_lead_count_missed_first_response,
  agentNotReplyFirst: formattedMessagesData.sales_agent_count_missed_first_response,
  agentAvgResponseTimeSecondsThisPeriod:
      formatTime(dados.sales_agent_avg_response_time_seconds),
  agentAvgResponseTimeSecondsThisPeriodNorm:
      formatTime(dados.sales_agent_avg_response_time_seconds_norm_this_period),
  agentAvgFirstResponseTimeSeconds: formatTime(dados.sales_agent_avg_first_response_time),
  agentAvgFirstResponseTimeSecondsNorm: formatTime(dados.sales_agent_avg_first_response_time_norm),
  countLastMessageWasAgent: formattedMessagesData.sales_count_last_message_was_agent,
  countLastMessageWasContact: formattedMessagesData.sales_count_last_message_was_lead,
  totalSentLinks: formattedMessagesData.sales_sent_links,
}// salesInboxes


const sdrLabels = dados.sdr_labels

const sdrLabelsQualificacao = {
  'baixa qualificacao': 0,
  'media qualificacao': 0,
  'alta qualificacao': 0,
  'sem interesse': 0,
}

const sdrLabelsNavios = {}

const sdrLabelsIgnore = {
  'em contato': true,
  'aguardando': true
}

for (let labelCountPair of sdrLabels) {
  const labelNorm = labelCountPair.label.replaceAll("_", " ");

  if (sdrLabelsIgnore[labelNorm] === true)
    continue
  else if (sdrLabelsQualificacao[labelNorm] != null) {
    sdrLabelsQualificacao[labelNorm] = formatNumber(labelCountPair.count, 0, 0);
  } else {
    sdrLabelsNavios[labelNorm] = formatNumber(labelCountPair.count, 0, 0);
  }
}

const salesWithoutInterestLst = dados.sales_labels.filter((e) => e.label == 'sem_interesse');
const salesWithoutInterest = salesWithoutInterestLst.length == 1 ? salesWithoutInterestLst[0].count : 0;

const percentSalesWithoutInterestOfActive = percentOf(salesWithoutInterest, dados.sales_active_conversations)

return {
  periodo: periodoAnalisado,
  periodoShort,
  percentSdrActiveConversationOfTotalActive,
  percentSdrEngagedOfActive,
  percentSdrNotEmptyNewConversationsnOfSdrActive,
  percentSdrEmptyNewConversationsnOfNewConversations,
  percentSdrAtLeastOneInteractionOfSdrActive,
  percentSdrMoreThanOneInteractionOfSdrActive,
  percentSdrThreeOrMoreInteractionOfSdrActive,
  percentSdrFiveOrMoreInteractionOfSdrActive,
  percentSdrTenOrMoreInteractionOfSdrActive,
  percentSdrAgentNotReplyLeadOfSdrActive,
  percentSdrAgentNotReplyFirstLeadOfSdrActive,
  percentSdrLeadNotReplyFirstAgentOfSdrActive,
  percentSdrAgentReplyLeadOfSdrActive,
  percentSdrAgentReplyLeadOnNewConversationOfSdrActive,
  percentQualifiedLeadsOfSdrEngagedLeads,
  percentQualifiedLeadsOfSdrActiveConversations,
  countResponseQualifiedFirstResponse,
  percentResponseFirstResponseOfQualifieds,
  convertions,
  percentConvertionOfQualifieds,
  frequencyHourTable,
  sortedFrequencies,
  frequencyWeekdayTable,
  sdrInboxTable,
  sdrLabelsQualificacao,
  sdrLabelsNavios,
  avgTimeToQualify,
  percentSalesNotEmptyNewConversationsnOfSalesActive,
  percentSalesEngagedOfActive,
  percentSalesAgentNotReplyFirstLeadOfSdrActive,
  percentSalesCountLastMessageWasLeadOfSdrActive,
  percentSalesLeadCountMissedFirstResponseOfActiveConversations,
  salesInboxTable,
  salesWithoutInterest,
  percentSalesWithoutInterestOfActive,
  ...formattedMessagesData
}

