// // variaveis de nós anteriores
const atualIndex = 1;
const anteriorIndex = 0;
const dadosPeriodoAtual = $("MessagesData").all()[atualIndex].json;
const dadosPeriodoAnterior = $("MessagesData").all()[anteriorIndex].json;

function compare(dataAtual, dataPrevious) {
  dataPrevious = Number(dataPrevious)
  dataAtual = Number(dataAtual)
  const difference = dataAtual - dataPrevious;
  let number = (100 * difference / dataPrevious);
  let formatPtBr = number.toLocaleString('pt-br', {
      minimumFractionDigits: 1,
      maximumFractionDigits: 2
  });
  return {number, formatPtBr}
} 

const comparativoSdrActiveConversations = 
  compare(dadosPeriodoAtual.sdr_active_conversations,
          dadosPeriodoAnterior.sdr_active_conversations)

const comparativoSalesActiveConversations = 
  compare(dadosPeriodoAtual.sales_active_conversations,
          dadosPeriodoAnterior.sales_active_conversations)

const comparativoSdrEngagedLeads = 
  compare(dadosPeriodoAtual.sdr_engaged_leads,
          dadosPeriodoAnterior.sdr_engaged_leads)

