  compare(dadosPeriodoAtual.sales_agent_avg_first_response_time,
          dadosPeriodoAnterior.sales_agent_avg_first_response_time);

const comparativoSalesAgentAvgFirstResponseTimeNorm =
  compare(dadosPeriodoAtual.sales_agent_avg_first_response_time_norm,
          dadosPeriodoAnterior.sales_agent_avg_first_response_time_norm)

